import React, { useState } from 'react';
import './styles.css';

const PracticeAreas = () => {
  const [selectedArea, setSelectedArea] = useState('Intellectual Property');

  const content = {
    "Intellectual Property": {
      title: "INTELLECTUAL PROPERTY (IP) PROSECUTION & PORTFOLIO MANAGEMENT",
      description: `We are experienced in all aspects of establishing, managing, and protecting all IP aspects including, trademarks, patents, industrial designs, and copyrights. We combine practical, efficient advice with cost-effective legal services for a broad range of IP issues because we understand that your IP are valuable assets that help define your unique corporate identity. We have handled IP Portfolios on behalf of a broad range of clients, including software industries, food and beverages, education services, fashions, IT companies, telecommunications, financial services, pharmacies, and consumer products. We have been closely working and collaborating with IP Agents in Singapore, Malaysia, Indonesia, Thailand, the Philippines, Vietnam, and Myanmar so that we will be able to serve our clients in all ten ASEAN countries, as well as other jurisdictions such as Japan, Hong Kong, and Australia.`,
    },
    "Suspension of Payment/Bankruptcy Law & Debt Recovery": {
      title: "SUSPENSION OF PAYMENT/BANKRUPTCY LAW & DEBT RECOVERY",
      description: "Content for Suspension of Payment/Bankruptcy Law & Debt Recovery will be added here.",
    },
    "Corporate and Investment": {
      title: "CORPORATE AND INVESTMENT",
      description: "Content for Corporate and Investment will be added here.",
    },
    "Mergers & Acquisitions": {
      title: "MERGERS & ACQUISITIONS",
      description: "Content for Mergers & Acquisitions will be added here.",
    },
    "Antitrust & Competition Law": {
      title: "ANTITRUST & COMPETITION LAW",
      description: "Content for Antitrust & Competition Law will be added here.",
    },
    "Dispute Resolution": {
      title: "DISPUTE RESOLUTION",
      description: "Content for Dispute Resolution will be added here.",
    },
    "Family Law": {
      title: "FAMILY LAW",
      description: "Content for Family Law will be added here.",
    },
    "Private Data Protection": {
      title: "PRIVATE DATA PROTECTION",
      description: "Content for Private Data Protection will be added here.",
    }
  };

  const handleClick = (area) => {
    setSelectedArea(area);
  };

  return (
    <div className="practice-areas-container">
      <div className="sidebar-left">
        <ul>
          {Object.keys(content).map((area) => (
            <li key={area} onClick={() => handleClick(area)}>
              {area}
            </li>
          ))}
        </ul>
      </div>
      
      <div className="sidebar-right">
        <div className="content">
          <h2>{content[selectedArea].title}</h2>
          <p>{content[selectedArea].description}</p>
        </div>
      </div>
    </div>
  );
}

export default PracticeAreas;
